/**
 * Tests for src/components/monitoring/web-vitals-reporter.tsx
 *
 * Tests the pure helper functions exported by the component.
 */

import {
  formatVitalLog,
  isActionable,
  buildReportPayload,
  uniqueMetricCount,
  BATCH_SIZE,
} from '@/components/monitoring/web-vitals-reporter';
import type { WebVitalMetric } from '@/lib/performance/web-vitals';

// ============================================================================
// Test data
// ============================================================================

function makeMetric(
  name: WebVitalMetric['name'],
  value: number,
  rating: WebVitalMetric['rating'] = 'good',
): WebVitalMetric {
  return {
    name,
    value,
    rating,
    navigationType: 'navigate',
    timestamp: 1700000000000,
  };
}

// ============================================================================
// formatVitalLog
// ============================================================================

describe('formatVitalLog', () => {
  it('formats CLS with 3 decimal places', () => {
    const log = formatVitalLog(makeMetric('CLS', 0.05));
    expect(log).toBe('[Web Vital] CLS: 0.050 (good)');
  });

  it('formats LCP in ms', () => {
    const log = formatVitalLog(makeMetric('LCP', 2500, 'good'));
    expect(log).toBe('[Web Vital] LCP: 2500ms (good)');
  });

  it('formats poor metrics', () => {
    const log = formatVitalLog(makeMetric('INP', 600, 'poor'));
    expect(log).toBe('[Web Vital] INP: 600ms (poor)');
  });

  it('rounds timing values', () => {
    const log = formatVitalLog(makeMetric('FID', 99.7, 'good'));
    expect(log).toBe('[Web Vital] FID: 100ms (good)');
  });
});

// ============================================================================
// isActionable
// ============================================================================

describe('isActionable', () => {
  it('returns false for good metrics', () => {
    expect(isActionable(makeMetric('LCP', 2000))).toBe(false);
  });

  it('returns true for needs-improvement metrics', () => {
    expect(isActionable(makeMetric('LCP', 3000, 'needs-improvement'))).toBe(true);
  });

  it('returns true for poor metrics', () => {
    expect(isActionable(makeMetric('LCP', 5000, 'poor'))).toBe(true);
  });
});

// ============================================================================
// buildReportPayload
// ============================================================================

describe('buildReportPayload', () => {
  it('includes pathname and metrics', () => {
    const metrics = [makeMetric('LCP', 2000), makeMetric('CLS', 0.1)];
    const payload = buildReportPayload(metrics, '/studio-pro');
    expect(payload.pathname).toBe('/studio-pro');
    expect(Array.isArray(payload.metrics)).toBe(true);
    expect((payload.metrics as unknown[]).length).toBe(2);
    expect(typeof payload.timestamp).toBe('number');
  });

  it('serialises metric fields correctly', () => {
    const metrics = [makeMetric('FCP', 1500, 'good')];
    const payload = buildReportPayload(metrics, '/');
    const m = (payload.metrics as Array<Record<string, unknown>>)[0];
    expect(m.name).toBe('FCP');
    expect(m.value).toBe(1500);
    expect(m.rating).toBe('good');
    expect(m.navigationType).toBe('navigate');
    expect(typeof m.timestamp).toBe('number');
  });
});

// ============================================================================
// uniqueMetricCount
// ============================================================================

describe('uniqueMetricCount', () => {
  it('counts unique metric names', () => {
    const metrics = [
      makeMetric('LCP', 2000),
      makeMetric('CLS', 0.1),
      makeMetric('LCP', 2500), // duplicate name
    ];
    expect(uniqueMetricCount(metrics)).toBe(2);
  });

  it('returns 0 for empty array', () => {
    expect(uniqueMetricCount([])).toBe(0);
  });

  it('returns 1 for single metric', () => {
    expect(uniqueMetricCount([makeMetric('FID', 50)])).toBe(1);
  });
});

// ============================================================================
// BATCH_SIZE
// ============================================================================

describe('BATCH_SIZE', () => {
  it('is a positive integer', () => {
    expect(Number.isInteger(BATCH_SIZE)).toBe(true);
    expect(BATCH_SIZE).toBeGreaterThan(0);
  });
});
